17â†’/**
18â†’ * Classify a session transcript using Claude CLI.
19â†’ * Returns one of the predefined tags based on the session content.
20â†’ */
21â†’export async function classifySession(
22â†’	content: string,
23â†’): Promise<SessionTag | undefined> {
